// Script Continued Below
(function executeRule(current, previous /*null when async*/) {
	var orgUnit = new GlideRecord('x_153465_discovert_discover_office_hierarchy');
	orgUnit.addQuery('office_abbreviation', current.discover_office_hierarchy.getDisplayValue());
	orgUnit.query();


	//OU HA
	if (current.is_office_administrator.changesTo('true')){ 
		if(orgUnit.next()){ 
			orgUnit.u_ou_hierarchy_administrators= orgUnit.u_ou_hierarchy_administrators+ ',' + current.office_member;
			orgUnit.update();
		}
	}

	if (current.is_office_administrator.changesTo('false')){ 
		if(orgUnit.next()){ 
			var ouHeirarchyAdmin = orgUnit.u_ou_hierarchy_administrators+ '';
			orgUnit.u_ou_hierarchy_administrators= ouHeirarchyAdmin.replaceAll(current.office_member,'');
			orgUnit.update();
		}
	}

})(current, previous);
